"use strict";(self.webpackChunkmd_vuepress=self.webpackChunkmd_vuepress||[]).push([[1264],{90006:(e,a,s)=>{s.r(a),s.d(a,{data:()=>l});const l={key:"v-164de646",path:"/superpowers/specs/2026-06-14-ai-reading-assistant-v1-design.html",title:"AI 阅读助手 v1 全链路优化设计",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"决策",slug:"决策",children:[]},{level:2,title:"已确认问题",slug:"已确认问题",children:[]},{level:2,title:"成功标准",slug:"成功标准",children:[]},{level:2,title:"构建分析 v1",slug:"构建分析-v1",children:[{level:3,title:"单一缓存快照",slug:"单一缓存快照",children:[]},{level:3,title:"哈希与失效",slug:"哈希与失效",children:[]},{level:3,title:"缓存恢复",slug:"缓存恢复",children:[]},{level:3,title:"构建输出",slug:"构建输出",children:[]}]},{level:2,title:"CI/CD v1",slug:"ci-cd-v1",children:[{level:3,title:"GitHub Pages",slug:"github-pages",children:[]},{level:3,title:"Vercel",slug:"vercel",children:[]}]},{level:2,title:"AI API v1",slug:"ai-api-v1",children:[]},{level:2,title:"页面零调用原则",slug:"页面零调用原则",children:[]},{level:2,title:"Chat 交互",slug:"chat-交互",children:[{level:3,title:"快捷 Tag",slug:"快捷-tag",children:[]},{level:3,title:"消息与输入",slug:"消息与输入",children:[]}]},{level:2,title:"响应式布局",slug:"响应式布局",children:[{level:3,title:"PC：≥ 1180px",slug:"pc-≥-1180px",children:[]},{level:3,title:"平板：768–1179px",slug:"平板-768–1179px",children:[]},{level:3,title:"手机：< 768px",slug:"手机-768px",children:[]},{level:3,title:"动画",slug:"动画",children:[]}]},{level:2,title:"摘要覆盖与无解析文章",slug:"摘要覆盖与无解析文章",children:[]},{level:2,title:"测试与验收",slug:"测试与验收",children:[{level:3,title:"自动测试",slug:"自动测试",children:[]},{level:3,title:"浏览器矩阵",slug:"浏览器矩阵",children:[]},{level:3,title:"测试环境",slug:"测试环境",children:[]}]}],git:{updatedTime:1781420858e3},filePathRelative:"superpowers/specs/2026-06-14-ai-reading-assistant-v1-design.md"}},56556:(e,a,s)=>{s.r(a),s.d(a,{default:()=>i});const l=(0,s(66252).uE)('<h1 id="ai-阅读助手-v1-全链路优化设计" tabindex="-1"><a class="header-anchor" href="#ai-阅读助手-v1-全链路优化设计" aria-hidden="true">#</a> AI 阅读助手 v1 全链路优化设计</h1><h2 id="决策" tabindex="-1"><a class="header-anchor" href="#决策" aria-hidden="true">#</a> 决策</h2><p>采用方案 A：静态缓存自举 + 内容分析哈希。一次性发布独立的 AI v1 构建与对话链路；旧接口继续兼容，但前端只接入 v1，避免在旧协议上反复渐进调整。</p><p>本设计替代 <code>2026-06-14-ai-reading-assistant-optimization-design.md</code> 中的覆盖式抽屉和旧接口渐进方案。</p><h2 id="已确认问题" tabindex="-1"><a class="header-anchor" href="#已确认问题" aria-hidden="true">#</a> 已确认问题</h2><ul><li>GitHub Actions 最新 master 构建当前成功，约 3–4 分钟；历史全量 AI 分析构建达到 30–38 分钟。</li><li>workflow 缓存 key 包含全部 Markdown 的总哈希，每次新增或编辑文章都会生成新 key。</li><li>线上缓存回填只恢复摘要，不恢复 manifest；Vercel 冷构建无法判断哪些文章未修改。</li><li>构建缓存命中不稳定，不能保证第二次相同构建零 AI 调用。</li><li>GitHub Actions 使用 Node 20，已出现 2026 年 6 月 16 日切换 Node 24 的弃用警告。</li><li>打开 AI 助手后，部分文章没有展示预分析内容；页面打开与运行时摘要兜底之间的边界不清晰。</li><li>PC 端原有潜入文档分栏符合阅读习惯，但当前小屏降级布局异常。</li><li>当前文章、本模块、联网检索被实现为硬模式控件，不符合自然对话体验。</li></ul><h2 id="成功标准" tabindex="-1"><a class="header-anchor" href="#成功标准" aria-hidden="true">#</a> 成功标准</h2><ol><li>连续两次对相同提交构建，第二次 AI API 调用数为 <code>0</code>。</li><li>仅修改一个可分析 Markdown 后，AI API 调用数为 <code>1</code>。</li><li>未修改文章的分析结果在 GitHub Actions 和 Vercel 冷构建中均可复用。</li><li>用户打开页面或展开助手时不调用任何 AI 后端接口。</li><li>默认展示构建阶段生成的文章摘要；没有可用摘要时展示明确的静态空状态，不自动实时生成。</li><li>只有用户发送对话才调用 <code>/api/ai/v1/*</code> 并消耗运行时 token。</li><li>PC 保持潜入文档分栏；平板使用覆盖侧栏；手机使用底部全屏面板。</li><li>320、375、390、768、1024、1440 像素宽度下无横向溢出、遮挡或不可操作控件。</li><li>GitHub Pages 与 Vercel 测试部署成功，构建过程使用 Node 24。</li></ol><h2 id="构建分析-v1" tabindex="-1"><a class="header-anchor" href="#构建分析-v1" aria-hidden="true">#</a> 构建分析 v1</h2><h3 id="单一缓存快照" tabindex="-1"><a class="header-anchor" href="#单一缓存快照" aria-hidden="true">#</a> 单一缓存快照</h3><p><code>summaries-v1.json</code> 是可部署、可恢复的完整快照：</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>\n  <span class="token property">&quot;version&quot;</span><span class="token operator">:</span> <span class="token number">1</span><span class="token punctuation">,</span>\n  <span class="token property">&quot;analysis&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token property">&quot;model&quot;</span><span class="token operator">:</span> <span class="token string">&quot;deepseek-v4-pro&quot;</span><span class="token punctuation">,</span>\n    <span class="token property">&quot;promptVersion&quot;</span><span class="token operator">:</span> <span class="token string">&quot;summary-v1&quot;</span><span class="token punctuation">,</span>\n    <span class="token property">&quot;extractVersion&quot;</span><span class="token operator">:</span> <span class="token string">&quot;markdown-v1&quot;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token property">&quot;files&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token property">&quot;/react/react16.md&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>\n      <span class="token property">&quot;sourceHash&quot;</span><span class="token operator">:</span> <span class="token string">&quot;sha256:...&quot;</span><span class="token punctuation">,</span>\n      <span class="token property">&quot;analysisHash&quot;</span><span class="token operator">:</span> <span class="token string">&quot;sha256:...&quot;</span><span class="token punctuation">,</span>\n      <span class="token property">&quot;status&quot;</span><span class="token operator">:</span> <span class="token string">&quot;success&quot;</span><span class="token punctuation">,</span>\n      <span class="token property">&quot;summary&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span>\n      <span class="token property">&quot;processedAt&quot;</span><span class="token operator">:</span> <span class="token string">&quot;...&quot;</span>\n    <span class="token punctuation">}</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token property">&quot;stats&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><p>不再依赖单独且可能丢失的 manifest。每个文件条目同时持有摘要与失效判定元数据。</p><h3 id="哈希与失效" tabindex="-1"><a class="header-anchor" href="#哈希与失效" aria-hidden="true">#</a> 哈希与失效</h3><ul><li><code>sourceHash</code>：规范化后的 Markdown 可分析内容哈希。</li><li><code>analysisHash</code>：<code>sourceHash + model + promptVersion + extractVersion</code> 的哈希。</li><li>仅以下情况调用 AI：没有条目、<code>analysisHash</code> 变化、上次状态不是 success。</li><li>Git diff 只用于输出诊断信息，不参与最终复用判断。</li><li>删除文章时删除对应缓存条目。</li><li>README、过短内容和明确排除目录生成确定性的本地状态，不调用 AI。</li></ul><h3 id="缓存恢复" tabindex="-1"><a class="header-anchor" href="#缓存恢复" aria-hidden="true">#</a> 缓存恢复</h3><p>恢复顺序：</p><ol><li>当前工作区 <code>.cache/ai-summaries-v1.json</code>。</li><li>GitHub Actions cache 恢复的快照。</li><li>上次成功部署的 <code>/summaries-v1.json</code>。</li><li>全新空快照。</li></ol><p>远程恢复拿到的单文件元数据足以直接判断复用，不再需要恢复另一份 manifest。</p><h3 id="构建输出" tabindex="-1"><a class="header-anchor" href="#构建输出" aria-hidden="true">#</a> 构建输出</h3><p>每次输出：总文件数、复用数、待分析数、短文跳过数、失败数、AI 调用数、命中率、分析耗时。<code>--dry-run</code> 只打印计划，绝不调用 AI。</p><p>没有 <code>AI_API_KEY</code> 时保留已恢复摘要；不能用空文件覆盖现有可用缓存。</p><h2 id="ci-cd-v1" tabindex="-1"><a class="header-anchor" href="#ci-cd-v1" aria-hidden="true">#</a> CI/CD v1</h2><h3 id="github-pages" tabindex="-1"><a class="header-anchor" href="#github-pages" aria-hidden="true">#</a> GitHub Pages</h3><ul><li>workflow 和 setup-node 使用 Node 24。</li><li>使用 <code>npm ci</code>，锁文件必须保持同步。</li><li>cache 使用稳定版本前缀和分支回退，不使用全部 Markdown 总哈希作为唯一 key。</li><li>AI 分析、VuePress 构建和 Pages 发布是可识别的独立步骤。</li><li>AI 分析失败时构建失败，不能以 <code>|| echo</code> 掩盖真实错误。</li><li>部署使用官方 Pages artifact 流程或已验证的 gh-pages 流程，避免重复发布链路。</li></ul><h3 id="vercel" tabindex="-1"><a class="header-anchor" href="#vercel" aria-hidden="true">#</a> Vercel</h3><ul><li>Vercel 构建调用同一 <code>build:ai:v1</code>，行为与 GitHub Actions 一致。</li><li>构建前从上次成功站点恢复 <code>summaries-v1.json</code>。</li><li>测试环境记录构建总耗时和 AI 调用数。</li><li>目标：无文章变化时不发生 AI 调用；VuePress 静态编译时间作为主要耗时。</li></ul><h2 id="ai-api-v1" tabindex="-1"><a class="header-anchor" href="#ai-api-v1" aria-hidden="true">#</a> AI API v1</h2><p>新增并冻结：</p><ul><li><code>POST /api/ai/v1/chat</code></li><li><code>POST /api/ai/v1/chat/stream</code></li></ul><p>v1 一次性提供：</p><ul><li>服务端所有 system prompt。</li><li>最近 6 轮对话裁剪。</li><li>文章或模块上下文字符预算。</li><li><code>max_tokens</code> 上限。</li><li>SSE 流式回答、停止生成、usage 和 sources。</li><li>联网检索仅在用户明确选择对应快捷 Tag 时启用。</li></ul><p>旧 <code>/api/ai/chat</code> 保持兼容，但新前端不再使用它。</p><h2 id="页面零调用原则" tabindex="-1"><a class="header-anchor" href="#页面零调用原则" aria-hidden="true">#</a> 页面零调用原则</h2><p>页面加载、摘要预取、助手展开和作用域选择均只访问站点静态资源：</p><ul><li><code>/summaries-v1.json</code></li><li><code>/module-index.json</code></li><li>当前页面 DOM</li></ul><p>不得调用 <code>/api/ai/*</code>。无构建摘要时显示“此文章暂无预分析内容”，并允许用户直接提问；发送问题后才调用 v1 Chat。</p><h2 id="chat-交互" tabindex="-1"><a class="header-anchor" href="#chat-交互" aria-hidden="true">#</a> Chat 交互</h2><h3 id="快捷-tag" tabindex="-1"><a class="header-anchor" href="#快捷-tag" aria-hidden="true">#</a> 快捷 Tag</h3><p>输入框上方展示可点击 Tag：</p><ul><li><code>当前文章</code></li><li><code>本模块</code></li><li><code>联网检索</code></li><li>根据文章摘要生成的 2–4 个建议问题</li></ul><p>点击 Tag 后向输入框插入可编辑的自然语言片段，例如：</p><ul><li><code>结合当前文章，</code></li><li><code>结合本模块相关文档，</code></li><li><code>联网检索最新资料后，</code></li></ul><p>Tag 仅辅助组织问题，不立即发送、不切换隐藏模式。请求参数从最终输入和已选择 Tag 派生，用户可组合多个 Tag。</p><h3 id="消息与输入" tabindex="-1"><a class="header-anchor" href="#消息与输入" aria-hidden="true">#</a> 消息与输入</h3><ul><li>默认首条内容是构建摘要卡片，不伪装成运行时回答。</li><li>Enter 发送，Shift+Enter 换行。</li><li>流式生成时发送按钮变为停止按钮。</li><li>支持重试、重新生成、复制与清空当前文章会话。</li><li>会话本地保存并限制大小；模型请求仅包含最近 6 轮。</li></ul><h2 id="响应式布局" tabindex="-1"><a class="header-anchor" href="#响应式布局" aria-hidden="true">#</a> 响应式布局</h2><h3 id="pc-≥-1180px" tabindex="-1"><a class="header-anchor" href="#pc-≥-1180px" aria-hidden="true">#</a> PC：≥ 1180px</h3><ul><li>保留潜入文档方式：文章容器平滑收窄，助手在同一 <code>.page</code> 网格内出现。</li><li>助手宽度在 400–520px 之间响应变化。</li><li>目录空间不足时收起右侧 TOC，但正文保持可读最小宽度。</li></ul><h3 id="平板-768–1179px" tabindex="-1"><a class="header-anchor" href="#平板-768–1179px" aria-hidden="true">#</a> 平板：768–1179px</h3><ul><li>助手成为右侧覆盖面板，不改变正文排版。</li><li>宽度 <code>min(520px, 88vw)</code>，带轻遮罩；点击遮罩或 Escape 收起。</li></ul><h3 id="手机-768px" tabindex="-1"><a class="header-anchor" href="#手机-768px" aria-hidden="true">#</a> 手机：&lt; 768px</h3><ul><li>从底部弹出，先显示约 76vh；可继续展开为全屏。</li><li>输入区固定在可视区域底部，适配 <code>env(safe-area-inset-bottom)</code> 和虚拟键盘。</li><li>320px 宽度下 Tag 横向滚动，按钮不挤压，消息不溢出。</li></ul><h3 id="动画" tabindex="-1"><a class="header-anchor" href="#动画" aria-hidden="true">#</a> 动画</h3><ul><li>PC 组合使用网格宽度、位移与透明度，缓动 <code>cubic-bezier(.22,1,.36,1)</code>。</li><li>平板从右侧滑入；手机从底部弹出。</li><li>消息进入使用短距离上移和淡入，不对长文本逐字模拟。</li><li><code>prefers-reduced-motion</code> 下关闭位移动画并缩短淡入。</li></ul><h2 id="摘要覆盖与无解析文章" tabindex="-1"><a class="header-anchor" href="#摘要覆盖与无解析文章" aria-hidden="true">#</a> 摘要覆盖与无解析文章</h2><ul><li>构建报告列出未生成摘要的 Markdown 路径和原因。</li><li>失败条目不标记为 success，下次构建自动重试。</li><li>增加覆盖率检查；非排除文章缺少 success 摘要时，测试构建失败。</li><li>线上助手严格按路径规范化匹配 <code>.html</code>、目录首页和 <code>.md</code> 缓存键。</li></ul><h2 id="测试与验收" tabindex="-1"><a class="header-anchor" href="#测试与验收" aria-hidden="true">#</a> 测试与验收</h2><h3 id="自动测试" tabindex="-1"><a class="header-anchor" href="#自动测试" aria-hidden="true">#</a> 自动测试</h3><ul><li>构建缓存：首次 N 次调用、第二次 0 次、改单篇 1 次、失败重试、删除清理、无 Key 保留缓存。</li><li>API v1：历史裁剪、上下文预算、流式事件顺序、停止、usage、旧 API 兼容。</li><li>前端：SSE 分块、Tag 插入与组合、页面打开零 Chat/summary API 请求、路径匹配。</li><li>构建：<code>npm ci</code>、AI 数据测试、VuePress build、bundle smoke。</li></ul><h3 id="浏览器矩阵" tabindex="-1"><a class="header-anchor" href="#浏览器矩阵" aria-hidden="true">#</a> 浏览器矩阵</h3><ul><li>320×568、375×812、390×844。</li><li>768×1024、1024×768。</li><li>1440×900、1920×1080。</li></ul><p>每个尺寸验证：展开/收起动画、摘要展示、Tag、输入、停止、滚动、横向溢出和控制台错误。</p><h3 id="测试环境" tabindex="-1"><a class="header-anchor" href="#测试环境" aria-hidden="true">#</a> 测试环境</h3><ul><li>GitHub Pages 测试分支完整通过。</li><li>Vercel Preview 完整通过。</li><li>连续两次部署证明第二次 AI 调用数为 0。</li><li>修改一个测试 Markdown 后证明 AI 调用数为 1。</li><li>记录部署 URL、构建耗时和缓存统计后才允许完成任务。</li></ul>',65),n={},i=(0,s(83744).Z)(n,[["render",function(e,a){return l}]])},83744:(e,a)=>{a.Z=(e,a)=>{const s=e.__vccOpts||e;for(const[e,l]of a)s[e]=l;return s}}}]);